// ActionFor(Severity) : SentinelAction
    public SentinelAction ActionFor(Detection.Severity severity) => severity switch
    {
        Detection.Severity.Critical => OnCritical,
        Detection.Severity.High     => OnHigh,
        Detection.Severity.Medium   => OnMedium,
        Detection.Severity.Low      => OnLow,
        _                           => SentinelAction.PassThrough
    };

// GetResponseAsync(IEnumerable<ChatMessage>, ChatOptions?, CancellationToken) : Task<ChatResponse>
    public override async Task<ChatResponse> GetResponseAsync(
        IEnumerable<ChatMessage> messages,
        ChatOptions? chatOptions = null,
        CancellationToken cancellationToken = default)
    {
        var messageList = messages as IReadOnlyList<ChatMessage> ?? messages.ToList();
        var sessionId = SessionId.New();

        // Scan the prompt
        var promptCtx = new SentinelContext(
            options.DefaultSenderId,
            options.DefaultReceiverId,
            sessionId,
            messageList,
            []);

        var promptResult = await pipeline.RunAsync(promptCtx, cancellationToken);
        await AppendAuditAsync(promptResult, messageList, cancellationToken);
        interventionEngine.Apply(promptResult, sessionId, options.DefaultSenderId, options.DefaultReceiverId);

        // Call the inner client
        var response = await base.GetResponseAsync(messageList, chatOptions, cancellationToken);

        // Scan the response
        IReadOnlyList<ChatMessage> responseMessages =
            response.Messages as IReadOnlyList<ChatMessage> ?? response.Messages.ToList();
        var responseCtx = new SentinelContext(
            options.DefaultReceiverId,
            options.DefaultSenderId,
            sessionId,
            responseMessages,
            []);

        var responseResult = await pipeline.RunAsync(responseCtx, cancellationToken);
        await AppendAuditAsync(responseResult, responseMessages, cancellationToken);
        interventionEngine.Apply(responseResult, sessionId, options.DefaultReceiverId, options.DefaultSenderId);

        return response;
    }

// GetStreamingResponseAsync(IEnumerable<ChatMessage>, ChatOptions?, CancellationToken) : IAsyncEnumerable<ChatResponseUpdate>
    public override async IAsyncEnumerable<ChatResponseUpdate> GetStreamingResponseAsync(
        IEnumerable<ChatMessage> messages,
        ChatOptions? chatOptions = null,
        [EnumeratorCancellation] CancellationToken cancellationToken = default)
    {
        var messageList = messages as IReadOnlyList<ChatMessage> ?? messages.ToList();
        var sessionId = SessionId.New();

        // 1. Scan prompt
        var ctx = new SentinelContext(
            options.DefaultSenderId,
            options.DefaultReceiverId,
            sessionId,
            messageList,
            []);

        var result = await pipeline.RunAsync(ctx, cancellationToken);
        await AppendAuditAsync(result, messageList, cancellationToken);
        interventionEngine.Apply(result, sessionId, options.DefaultSenderId, options.DefaultReceiverId);

        // 2. Collect streamed chunks
        var chunks = new System.Text.StringBuilder();
        await foreach (var update in base.GetStreamingResponseAsync(messageList, chatOptions, cancellationToken))
        {
            chunks.Append(update.Text ?? "");
            yield return update;
        }

        // 3. Scan aggregated response
        var responseText = chunks.ToString();
        if (!string.IsNullOrEmpty(responseText))
        {
            var responseMessages = new List<ChatMessage> { new(ChatRole.Assistant, responseText) };
            var responseCtx = new SentinelContext(
                options.DefaultReceiverId,
                options.DefaultSenderId,
                sessionId,
                responseMessages,
                []);
            var responseResult = await pipeline.RunAsync(responseCtx, cancellationToken);
            await AppendAuditAsync(responseResult, responseMessages, cancellationToken);
            interventionEngine.Apply(responseResult, sessionId, options.DefaultReceiverId, options.DefaultSenderId);
        }
    }

// AppendAuditAsync(PipelineResult, IReadOnlyList<ChatMessage>, CancellationToken) : Task
    private async Task AppendAuditAsync(
        PipelineResult result,
        IReadOnlyList<ChatMessage> msgs,
        CancellationToken cancellationToken)
    {
        foreach (var detection in result.Detections)
        {
            var content = msgs.LastOrDefault()?.Text ?? "";
            var hash = ComputeHash(content);
            var entry = new AuditEntry(
                Guid.NewGuid().ToString("N"),
                DateTimeOffset.UtcNow,
                hash,
                null,
                detection.Severity,
                detection.DetectorId.ToString(),
                detection.Reason);
            await auditStore.AppendAsync(entry, cancellationToken);
        }
    }

// ComputeHash(string) : string
    private static string ComputeHash(string input)
    {
        var bytes = SHA256.HashData(Encoding.UTF8.GetBytes(input));
        return Convert.ToHexString(bytes).ToLowerInvariant();
    }

// SentinelAction
public enum SentinelAction
{
    /// <summary>
    /// Allow the message through with no logging or notification.
    /// No mediator notification is published.
    /// </summary>
    PassThrough,

    /// <summary>
    /// Allow the message through and publish mediator notifications
    /// (<see cref="Intervention.ThreatDetectedNotification"/> and
    /// <see cref="Intervention.InterventionAppliedNotification"/>).
    /// Wire up notification handlers in the consuming application to record, aggregate, or forward events.
    /// </summary>
    Log,

    /// <summary>
    /// Allow the message through and publish mediator notifications, identical to <see cref="Log"/>.
    /// By convention, <c>Alert</c> signals that the consuming application's notification handlers
    /// should take an active alerting action (e.g. page on-call, send a Slack message).
    /// The distinction from <see cref="Log"/> is enforced by the handlers you register, not by AI.Sentinel itself.
    /// </summary>
    Alert,

    /// <summary>
    /// Block the message by throwing <see cref="Intervention.SentinelException"/>.
    /// Mediator notifications are still published before the exception is thrown.
    /// </summary>
    Quarantine
}

