        await ctx.Response.WriteAsync(sb.ToString());
    }

// TrsStreamAsync(HttpContext) : Task
    public static async Task TrsStreamAsync(HttpContext ctx)
    {
        ctx.Response.Headers["Content-Type"] = "text/event-stream";
        ctx.Response.Headers["Cache-Control"] = "no-cache";
        ctx.Response.Headers["X-Accel-Buffering"] = "no";

        var store = ctx.RequestServices.GetRequiredService<IAuditStore>();

        while (!ctx.RequestAborted.IsCancellationRequested)
        {
            try
            {
                var entries = new List<AuditEntry>();
                await foreach (var e in store.QueryAsync(new AuditQuery(), ctx.RequestAborted))
                    entries.Add(e);

                var scoreInputs = entries.Select(e => new ThreatRiskScore(e.Severity switch
                {
                    Severity.Critical => 100,
                    Severity.High     => 70,
                    Severity.Medium   => 40,
                    Severity.Low      => 15,
                    _                 => 0
                }));

                var trs = ThreatRiskScore.Aggregate(scoreInputs);
                var json = JsonSerializer.Serialize(new { value = trs.Value, stage = trs.Stage.ToString() });
                await ctx.Response.WriteAsync($"data: {json}\n\n", ctx.RequestAborted);
                await ctx.Response.Body.FlushAsync(ctx.RequestAborted);
                await Task.Delay(2000, ctx.RequestAborted);
            }
            catch (OperationCanceledException) { break; }
        }
    }

// StaticFileAsync(HttpContext) : Task
    public static Task StaticFileAsync(HttpContext ctx)
    {
        var file = (string?)ctx.Request.RouteValues["file"] ?? "";

        if (!AllowedStaticFiles.Contains(file))
        {
            ctx.Response.StatusCode = 404;
            return Task.CompletedTask;
        }

        var content = ReadEmbedded(file);
        if (string.IsNullOrEmpty(content))
        {
            ctx.Response.StatusCode = 404;
            return Task.CompletedTask;
        }
        ctx.Response.ContentType = file.EndsWith(".css") ? "text/css" : "application/javascript";
        return ctx.Response.WriteAsync(content);
    }

// ReadEmbedded(string) : string
    private static string ReadEmbedded(string filename)
    {
        var asm = Assembly.GetExecutingAssembly();
        var name = asm.GetManifestResourceNames()
            .FirstOrDefault(n => n.EndsWith(filename.Replace('/', '.').Replace('\\', '.'),
                StringComparison.OrdinalIgnoreCase));
        if (name is null) return string.Empty;
        using var stream = asm.GetManifestResourceStream(name)!;
        using var reader = new StreamReader(stream);
        return reader.ReadToEnd();
    }

// AppendAsync(AuditEntry, CancellationToken) : ValueTask
    public async ValueTask AppendAsync(AuditEntry entry, CancellationToken ct)
    {
        await _lock.WaitAsync(ct);
        try
        {
            // Overwrite oldest when full (ring buffer semantics)
            if (_buffer.IsFull)
                _buffer.TryRead(out _);
            _buffer.TryWrite(entry);
        }
        finally { _lock.Release(); }
    }

// QueryAsync(AuditQuery, CancellationToken) : IAsyncEnumerable<AuditEntry>
    public async IAsyncEnumerable<AuditEntry> QueryAsync(
        AuditQuery query,
        [EnumeratorCancellation] CancellationToken ct)
    {
        await _lock.WaitAsync(ct);
        AuditEntry[] snapshot;
        try { snapshot = _buffer.ToArray(); }
        finally { _lock.Release(); }

        int yielded = 0;
        foreach (var entry in snapshot)
        {
            if (ct.IsCancellationRequested) yield break;
            if (yielded >= query.PageSize) yield break;
            if (query.MinSeverity.HasValue && entry.Severity < query.MinSeverity) continue;
            if (query.From.HasValue && entry.Timestamp < query.From) continue;
            if (query.To.HasValue && entry.Timestamp > query.To) continue;
            yield return entry;
            yielded++;
        }
    }

