// Entropy(string) : double
    private static double Entropy(string s)
    {
        if (s.Length == 0) return 0;
        var freq = s.GroupBy(c => c).Select(g => (double)g.Count() / s.Length);
        return -freq.Sum(p => p * Math.Log2(p));
    }

